// lib/demo-recent-data.ts
// АВТОСГЕНЕРИРОВАНО из реальной боевой БД (data/sqlite.db) — снимок за последние
// 3 дня реальной активности (создан 2026-07-10), с анонимизацией:
//   - грузополучатели/заказчики/поставщики заменены на вымышленные названия
//   - районы ПК (Озерский, Талдомский и т.п.) заменены на вымышленные
//   - водители заменены на вымышленные ФИО
//   - госномера прогнаны через побуквенный/поцифровой шифр-подстановку
//   - тоннаж, время, материалы, связи Вып/Заяв — настоящие (из реальных данных)
// Даты хранятся как смещение в днях от момента генерации (dayOffset) и
// пересчитываются в lib/demo-data.ts через daysAgo(), чтобы демо всегда
// выглядело свежим, а не залипало на дате генерации.

export interface RecentShipmentRaw {
  number: string;
  division: string;
  customer: string;
  consignee: string;
  material: string;
  quantity: number;
  driver: string | null;
  licensePlate: string | null;
  clientRequestNumber: string | null;
  dayOffset: number;
  hour: number;
  minute: number;
  second: number;
}

export interface RecentRequestRaw {
  number: string;
  division: string;
  customer: string;
  consignee: string;
  material: string;
  quantity: number;
  closed: boolean;
  dayOffset: number;
  hour: number;
  minute: number;
  second: number;
}

export interface RecentIncomingRaw {
  number: string;
  division: string;
  supplier: string;
  material: string;
  gross: number | null;
  tara: number | null;
  quantity: number;
  driver: string | null;
  licensePlate: string | null;
  dayOffset: number;
  hour: number;
  minute: number;
  second: number;
}

